int
tse_task_schedule(tse_task_t *task, bool ready)
{
	struct tse_task_private  *dtp = tse_task2priv(task);
	struct tse_sched_private *dsp = dtp->dtp_sched;
	int rc = 0;

	if (ready && dtp->dtp_func == NULL)
		return -DER_INVAL;

	/* Add task to scheduler */
	pthread_mutex_lock(&dsp->dsp_lock);
	if (dtp->dtp_func == NULL || ready) {
		/** If task has no body function, mark it as running */
		dsp->dsp_inflight++;
		dtp->dtp_running = 1;
		daos_list_add_tail(&dtp->dtp_list, &dsp->dsp_running_list);

		/** +1 in case task is completed in body function */
		if (ready)
			tse_task_addref_locked(dtp);
	} else {
		/** Otherwise, scheduler will process it from init list */
		daos_list_add_tail(&dtp->dtp_list, &dsp->dsp_init_list);
	}
	tse_sched_addref_locked(dsp);
	pthread_mutex_unlock(&dsp->dsp_lock);

	/** if ready to be executed, call the task body function */
	if (ready) {
		dtp->dtp_func(task);

		/** If task was completed return the task result */
		if (dtp->dtp_complete)
			rc = task->dt_result;

		tse_task_decref(task);
	}

	return rc;
}

void amplifyAudio(Audio *audio, Edit *edit)
{
  int samples;
  int i = 0;
  int new;
  int max = INT16_MAX;
  int min = INT16_MIN;
  int16_t *start;
  
  assert(audio && edit);
  
  if(edit->amplification <= 0.0f) terminate("Amplification factor should be more than 0.");

  //will only handle 16 bit samples
  if(audio->fmt->bitsPerSample != 16)
  {
    printf("Unable to amplify audio with a sample length of %d bits.\n", audio->fmt->bitsPerSample);
    return;
  }
  
  printf("Amplifying audio by %.2f...\n", edit->amplification);
  
  start = (int16_t *) (&audio->data->data);
  samples = (int) (audio->data->size / sizeof(int16_t));
    
  while(i < samples)
  {
    new = (int) (*(start + i) * edit->amplification);
    if(new > max) *(start + i) = max;
    else if(new < min) *(start + i) = min;
    else *(start + i) = new;
    i++;
  }
}

