}

struct args *
args_create(int argc, ...)
{
	struct args	*args;
	va_list		 ap;
	int		 i;

	args = xcalloc(1, sizeof *args);
	if ((args->flags = bit_alloc(SCHAR_MAX)) == NULL)
		fatal("bit_alloc failed");

	args->argc = argc;
	if (argc == 0)
		args->argv = NULL;
	else
		args->argv = xcalloc(argc, sizeof *args->argv);

	va_start(ap, argc);
	for (i = 0; i < argc; i++)
		args->argv[i] = xstrdup(va_arg(ap, char *));
	va_end(ap);

	return (args);
}

static int countCommands(char* source) {
  int sum = 0;
  int i = 0;

  for(;;) {
    if(source[i] == ',') sum++;
    if(source[i] == '\0') return sum + 1; // account for last command without a trailing ,
    i++;
  }
}

int	search_value_just_above(int *value_beside, int *pos, int value, t_stack *b)
{
	t_list	*lst;
	int		num;
	int		count;
	int		ret;

	lst = b->stack;
	count = 0;
	ret = 1;
	while (b->stack != NULL)
	{
		num = ft_atoi(b->stack->content);
		if (value < num)
		{
			if (ret == 1 || (ret == 0 && num < *value_beside))
				save_value(value_beside, pos, num, count);
			ret = 0;
		}
		count++;
		b->stack = b->stack->next;
	}
	b->stack = lst;
	return (2);
}

int main(int argc, char const *argv[], char *envp[])
{
    char s[1024];
    list_t* pids = list_init();
    int pid;

    while(1) {
        printf("$ ");
        fflush(stdout);
        if(fgets(s, 1024, stdin) != NULL) {
            list_t* list = parse(s);
            if(list == NULL) {
                printf("Invalid input!\n");
                continue;
            }
            // print_list(list);
            if(strcmp(s, "exit\n") == 0) {
                return 0;
            }
            else {
                char* input_file = get_input_file(list);
                char* output_file = get_output_file(list);
                int has_pipe = find_pipe(list);
                char** args;
                char* name;
                int id = -1;
                int pipes[2];
                if(has_pipe == -1) {
                    args = list_to_args_array(list);
                    #ifdef DEBUG
                        pid = 0;
                    #else
                        pid = fork();
                    #endif
                    if(pid != 0) {
                        int pid_copy = malloc(sizeof(int));
                        pid_copy = pid;
                        list_append(pids, pid_copy);
                    }
                }
                else {
                    // We have a pipe, need to start two processes
                    int pid2;
                    char*** args_both = split_args(list);
                    pipe(pipes);
                    pid = fork();
                    if(pid == 0) {
                        args = args_both[0];
                        id = 0;
                    } else {
                        int pid_copy = malloc(sizeof(int));
                        pid_copy = pid;
                        list_append(pids, pid_copy);
                    }
                    pid2 = fork();
                    if(pid2 == 0) {
                        args = args_both[1];
                        id = 1;
                        pid = 0;
                    } else {
                        int pid_copy = malloc(sizeof(int));
                        pid_copy = pid2;
                        list_append(pids, pid_copy);
                    }
                }
                if(pid == 0) {
                    if(input_file != NULL) {
                        close(0);
                        open(input_file, O_RDONLY);
                    }
                    if(output_file != NULL) {
                        close(1);
                        open(output_file, O_WRONLY | O_TRUNC | O_CREAT, S_IRUSR | S_IWUSR);
                    }

                    if(has_pipe != -1) {
                        if(id == 0) {
                            printf("Reached 1\n");
                            fflush(1);
                            dup2(1, pipes[1]);
                            close(pipes[0]);
                        }
                        else if(id == 1) {
                            printf("Reached 2\n");
                            fflush(1);
                            dup2(0, pipes[0]);
                            close(pipes[1]);
                        }
                    }

                    name = args[0];

                    if(strchr(name, '/') != NULL) {
                        char* last_slash_ptr = strrchr(name, '/');
                        int last_slash = last_slash_ptr - name;
                        char* new_name = (char*) malloc((strlen(name) - last_slash) * sizeof(char) +1);
                        new_name = strncpy(new_name, name+last_slash+1, strlen(name) - last_slash);
                        args[0] = new_name;
                        if(execve(name, args, envp) == -1) {
                            printf("ERROR\n");
                            kill_processes(pids);
                            return -1;
                        }
                    }

                    // Parse PATH
                    list_t* path_list = list_init();
                    char* ptr;

                    char* PATH = malloc(strlen(getenv("PATH")) + 1);
                    strcpy(PATH, getenv("PATH"));
                    ptr = strtok(PATH, ":");
                    int len;
                    while(ptr != NULL) {
                        len = strlen(ptr);
                        char* buffer = (char*) malloc(len * sizeof(char)+1);
                        strncpy(buffer, ptr, len+1);
                        list_append(path_list, buffer);
                        ptr = strtok(NULL, ":");
                    }

                    // print_list(path_list);

                    char** paths = list_to_array(path_list);
                    int num_paths = list_len(path_list);
                    // Iterate through paths
                    char path[1024];
                    for(int i=0; i<num_paths; i++) {
                        char* cur_path = paths[i];
                        snprintf(path, 1024, "%s/%s", cur_path, name);
                        if(execve(path, args, envp) == -1) {
                            continue;
                        }
                        else {
                            return 0;
                        }

                    }
                    kill_processes(pids);
                    printf("ERROR\n");
                    return -1;
                }
                else {
                    if(id == -1 && has_pipe != -1) {
                        close(pipes[0]);
                        close(pipes[1]);
                    }
                    wait_on_list(pids);
                    fflush(stdout);
                }
            }

        }

    }
    return 0;

}

int		get_value_index(t_stack **head, int value)
{
	int		index;
	t_stack *count;

	index = 1;
	count = (*head);
	while (count != NULL)
	{
		if (count->n == value)
			return (index);
		count = count->next;
		index++;
	}
	return (0);
}
